#include<bits/stdc++.h>
using namespace std;
long long a,b,c;
int f[21][21][21];
int main() {
	for(int i=0; i<=20; i++) {
		for(int j=0; j<=20; j++) {
			for(int k=0; k<=20; k++) {
				if(i==0||k==0||j==0)f[i][j][k]=1;
				else if(i<j&&j<k)
					f[i][j][k]=f[i][j][k-1]+f[i][j-1][k-1]-f[i][j-1][k];
				else
					f[i][j][k]=f[i-1][j][k]+f[i-1][j-1][k]+f[i-1][j][k-1]-f[i-1][j-1][k-1];
			}
		}
	}
	while(cin>>a>>b>>c) {
		if(a==-1&&b==-1&&c==-1)break;
		cout<<"w("<<a<<", "<<b<<", "<<c<<") = ";
		if(a<=0||b<=0||c<=0)a=b=c=0;
		if(a>20||b>20||c>20)a=b=c=20;
		cout<<f[a][b][c]<<endl;
	}
	return 0;
}
